  const allProducts = [...recentProducts, ...bestSellers];

  const renderPage = () => {
    switch (currentPage) {
      case 'shop':
        return <Shop allProducts={allProducts} />;
      case 'home':
      default:
        return (
          <>
            <Hero />
            <FeaturedServices />

            <SearchSection onSearch={handleSearch} />

            {searchResults ? (
