  return (
    <CartProvider>
      <div className="App">
        <Navbar 
          currentPage={currentPage}
          setCurrentPage={setCurrentPage}
          openAppointmentModal={() => setIsAppointmentModalOpen(true)}
        />

        {renderPage()}

        <AppointmentBooking 
          isOpen={isAppointmentModalOpen}
          onClose={() => setIsAppointmentModalOpen(false)}
        />
      </div>
    </CartProvider>
  );
}

export default App;
